package com.google.gson.internal.bind;
import com.google.gson.Gson;
import com.google.gson.JsonDeserializationContext;
import com.google.gson.JsonDeserializer;
import com.google.gson.JsonElement;
import com.google.gson.JsonParseException;
import com.google.gson.JsonSerializationContext;
import com.google.gson.JsonSerializer;
import com.google.gson.internal.Streams;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Type;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.TypeAdapterFactory;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.$Gson$Preconditions;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class TreeTypeAdapterTest {

  @Test
  void newTypeHierarchyFactory_shouldReturnSingleTypeFactoryWithCorrectParams() throws Exception {
    Class<?> hierarchyType = String.class;
    TypeAdapter<?> typeAdapter = mock(TypeAdapter.class);

    // The error is caused by passing a mocked TypeAdapter which is not an instance of JsonSerializer or JsonDeserializer,
    // but the method expects one of these or a TypeAdapter wrapped as Object.
    // The method newTypeHierarchyFactory expects an Object that is either a JsonSerializer, JsonDeserializer, or TypeAdapter.
    // Passing a mocked TypeAdapter directly causes the precondition check to fail.
    // Instead, pass the mock wrapped as Object to avoid the precondition failure.

    // Actually, the method signature is: newTypeHierarchyFactory(Class<?> hierarchyType, Object typeAdapter)
    // So passing the mock is fine, but the internal check expects the typeAdapter to be an instance of JsonSerializer or JsonDeserializer or TypeAdapter.
    // The mock is a TypeAdapter, so it should be accepted.
    // However, the error suggests the precondition fails, likely because the mock is not a valid type for the internal check.

    // To fix, mock a JsonSerializer or JsonDeserializer instead of TypeAdapter.
    // Let's mock a JsonSerializer and pass it instead.

    Object serializerMock = mock(com.google.gson.JsonSerializer.class);

    TypeAdapterFactory factory = TreeTypeAdapter.newTypeHierarchyFactory(hierarchyType, serializerMock);

    assertNotNull(factory);

    Class<?> singleTypeFactoryClass = factory.getClass();

    Field typeAdapterField = singleTypeFactoryClass.getDeclaredField("typeAdapter");
    typeAdapterField.setAccessible(true);

    Field hierarchyTypeField = singleTypeFactoryClass.getDeclaredField("hierarchyType");
    hierarchyTypeField.setAccessible(true);

    Field matchRawTypeField = singleTypeFactoryClass.getDeclaredField("matchRawType");
    matchRawTypeField.setAccessible(true);

    Field exactTypeField = singleTypeFactoryClass.getDeclaredField("exactType");
    exactTypeField.setAccessible(true);

    assertSame(serializerMock, typeAdapterField.get(factory));
    assertNull(exactTypeField.get(factory));
    assertFalse((Boolean) matchRawTypeField.get(factory));
    assertSame(hierarchyType, hierarchyTypeField.get(factory));
  }
}
